 41→export function useWindow(options: UseWindowOptions = {}) {
 42→  const onShowRef = useRef(options.onShow);
 43→  const onHideRef = useRef(options.onHide);
 44→  const onTrayNavigateRef = useRef(options.onTrayNavigate);
 45→
 46→  useEffect(() => {
 47→    onShowRef.current = options.onShow;
 48→    onHideRef.current = options.onHide;
 49→    onTrayNavigateRef.current = options.onTrayNavigate;
 50→  });
 51→
 52→  useEffect(() => {
 53→    if (!isTauri) return;
 54→
 55→    let unlistenFocus: (() => void) | undefined;
 56→    let unlistenTray: (() => void) | undefined;
 57→    let cancelled = false;
 58→
 59→    (async () => {
 60→      const { getCurrentWindow } = await import('@tauri-apps/api/window');
 61→      const { listen } = await import('@tauri-apps/api/event');
 62→      const appWindow = getCurrentWindow();
 63→
 64→      await syncStoredPositionToBackend();
 65→
 66→      const focusUnsub = await appWindow.onFocusChanged(({
 67→        payload: focused,
 68→      }) => {
 69→        if (focused) {
 70→          onShowRef.current?.();
 71→        } else {
 72→          onHideRef.current?.();
 73→        }
 74→      });
 75→
 76→      const trayUnsub = await listen<string>('tray-navigate', event => {
 77→        onTrayNavigateRef.current?.(event.payload);
 78→      });
 79→
 80→      if (cancelled) {
 81→        focusUnsub();
 82→        trayUnsub();
 83→      } else {
 84→        unlistenFocus = focusUnsub;
 85→        unlistenTray = trayUnsub;
 86→      }
 87→    })();
 88→
 89→    return () => {
 90→      cancelled = true;
 91→      unlistenFocus?.();
 92→      unlistenTray?.();
 93→    };
 94→  }, []);
 95→
 96→  const hideWindow = useCallback(async () => {
 97→    if (!isTauri) return;
 98→    const { getCurrentWindow } = await import('@tauri-apps/api/window');
 99→    await getCurrentWindow().hide();
100→  }, []);
101→
102→  const setPositionPreference = useCallback(async (position: string) => {
103→    if (!isTauri) return;
104→    const { invoke } = await import('@tauri-apps/api/core');
105→    await invoke('set_window_position_pref', { position });
106→  }, []);
107→
108→  return {
109→    hideWindow,
110→    setPositionPreference,
111→    isTauri,
112→  };
113→}
