 7→export function storageGet<T>(
 8→  key: string,
 9→  validate: (value: unknown) => value is T,
10→): T | null {
11→  try {
12→    const raw = localStorage.getItem(prefixKey(key));
13→    if (raw === null) return null;
14→    const parsed: unknown = JSON.parse(raw);
15→    return validate(parsed) ? parsed : null;
