 4→type ThemePreference = 'dark' | 'light' | 'system';
 5→type ResolvedTheme = 'dark' | 'light';
 6→
 7→const STORAGE_KEY = 'theme';
 8→
 9→function isThemePreference(value: unknown): value is ThemePreference {
10→  return value === 'dark' || value === 'light' || value === 'system';
11→}
12→
13→function getSystemTheme(): ResolvedTheme {
14→  return window.matchMedia('(prefers-color-scheme: light)').matches
15→    ? 'light'
16→    : 'dark';
17→}
18→
19→function resolveTheme(preference: ThemePreference): ResolvedTheme {
20→  return preference === 'system' ? getSystemTheme() : preference;
21→}
22→
23→function loadPreference(): ThemePreference {
24→  const fromStorage = storageGet(STORAGE_KEY, isThemePreference);
25→  if (fromStorage) return fromStorage;
26→
27→  try {
28→    const raw = localStorage.getItem('raycast-theme');
29→    if (raw && isThemePreference(raw)) {
30→      storageSet(STORAGE_KEY, raw);
31→      return raw;
32→    }
33→  } catch {
34→    // unavailable
35→  }
36→  return 'dark';
37→}
38→
39→function applyTheme(theme: ResolvedTheme) {
40→  document.documentElement.setAttribute('data-theme', theme);
41→}
42→
43→export function useTheme() {
44→  const [preference, setPreference] = useState<ThemePreference>(loadPreference);
45→  const [resolved, setResolved] = useState<ResolvedTheme>(() =>
46→    resolveTheme(preference));
47→
48→  useEffect(() => {
49→    const r = resolveTheme(preference);
50→    setResolved(r);
51→    applyTheme(r);
52→  }, [preference]);
53→
54→  useEffect(() => {
55→    if (preference !== 'system') return;
56→
57→    const mql = window.matchMedia('(prefers-color-scheme: light)');
58→    const handler = () => {
59→      const r = resolveTheme('system');
60→      setResolved(r);
61→      applyTheme(r);
62→    };
63→    mql.addEventListener('change', handler);
64→    return () => mql.removeEventListener('change', handler);
65→  }, [preference]);
66→
67→  const setTheme = useCallback((value: ThemePreference) => {
68→    setPreference(value);
69→    storageSet(STORAGE_KEY, value);
70→  }, []);
71→
72→  return {
73→    preference,
74→    resolved,
75→    setTheme,
76→  };
77→}
